import{_ as o,o as t,c as a,a2 as i}from"./chunks/framework.DGS7qFRZ.js";const u=JSON.parse('{"title":"Play quirks","description":"","frontmatter":{},"headers":[],"relativePath":"quirks.md","filePath":"quirks.md","lastUpdated":1782037448000}'),s={name:"quirks.md"};function r(n,e,c,d,l,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="play-quirks" tabindex="-1">Play quirks <a class="header-anchor" href="#play-quirks" aria-label="Permalink to &quot;Play quirks&quot;">​</a></h1><p>Non-obvious behaviour from the Google Play Developer API that the CLI works around. Each entry includes what the API does, what we do about it, and what to remember when you go beyond the CLI.</p><h2 id="_1-legacy-inappproducts-api-is-dead" tabindex="-1">1. Legacy <code>inappproducts</code> API is dead <a class="header-anchor" href="#_1-legacy-inappproducts-api-is-dead" aria-label="Permalink to &quot;1. Legacy `inappproducts` API is dead&quot;">​</a></h2><p>For newer accounts, the legacy <code>inappproducts</code> resource (managed products via the pre-2023 API) returns <strong>403 &quot;Please migrate to the new publishing API&quot;</strong> on every call. The CLI uses <code>monetization.onetimeproducts</code> exclusively — the new API surface introduced in 2023.</p><p>This required upgrading <code>googleapis</code> to ≥ 173.0.0 to get the <code>monetization.onetimeproducts</code> resource class.</p><p>If you&#39;re reading old documentation or example code that uses <code>inappproducts.list()</code>, ignore it. The replacement is:</p><ul><li><code>monetization.onetimeproducts.list()</code></li><li><code>monetization.onetimeproducts.get(productId)</code></li><li><code>monetization.onetimeproducts.patch(productId, body, regionsVersion, allowMissing)</code></li><li><code>monetization.onetimeproducts.purchaseOptions.batchUpdateStates()</code></li><li><code>monetization.onetimeproducts.purchaseOptions.offers.{activate, deactivate, list}</code></li></ul><h2 id="_2-pricing-is-concrete-per-region-not-anchor-tier" tabindex="-1">2. Pricing is concrete per region, not anchor + tier <a class="header-anchor" href="#_2-pricing-is-concrete-per-region-not-anchor-tier" aria-label="Permalink to &quot;2. Pricing is concrete per region, not anchor + tier&quot;">​</a></h2><p>Where Apple has a tier table you reference by ID, Play takes a literal <code>Money { currency_code, units, nanos }</code> per region. There&#39;s no &quot;auto-equalise&quot; mechanism beyond <code>newRegionsConfig</code> (USD + EUR fallback for any region Play opens in future that&#39;s not already in your <code>regionalConfigs</code>).</p><p>This means a price change in YAML usually means editing many <code>regional_configs</code> entries — <code>iap export</code> writes them all explicitly. The deep-diff walker matches by <code>region</code> so reordering doesn&#39;t register as drift.</p><p>Currency must match the region&#39;s local currency. <code>regional_configs: [{ region: GB, price: { currency_code: USD, ... } }]</code> is rejected by Play.</p><h2 id="_3-region-codes-are-iso-2" tabindex="-1">3. Region codes are ISO-2 <a class="header-anchor" href="#_3-region-codes-are-iso-2" aria-label="Permalink to &quot;3. Region codes are ISO-2&quot;">​</a></h2><p><code>US</code>, <code>DE</code>, <code>GB</code>, <code>FR</code>, <code>JP</code> — not <code>USA</code>, <code>DEU</code>, <code>GBR</code> like Apple. If you&#39;re cross-porting from appstore-cli YAML, you&#39;ll need to map.</p><h2 id="_4-no-subscription-groups" tabindex="-1">4. No subscription groups <a class="header-anchor" href="#_4-no-subscription-groups" aria-label="Permalink to &quot;4. No subscription groups&quot;">​</a></h2><p>Apple has <code>subscription_groups</code> (a sub belongs to a group; users can only have one sub per group at a time). Play has no such concept — each subscription stands alone. The YAML schema has no <code>subscription_groups</code> top-level.</p><p>If you&#39;re migrating logic from Apple, upgrade ladders are implemented via <strong>multiple base plans</strong> within one subscription instead.</p><h2 id="_5-one-time-purchase-options-have-no-single-activate-deactivate" tabindex="-1">5. One-time PURCHASE OPTIONS have no single activate/deactivate <a class="header-anchor" href="#_5-one-time-purchase-options-have-no-single-activate-deactivate" aria-label="Permalink to &quot;5. One-time PURCHASE OPTIONS have no single activate/deactivate&quot;">​</a></h2><p>Sub base plans, sub offers, and one-time offers all have dedicated <code>activate</code> / <code>deactivate</code> endpoints. <strong>One-time purchase options don&#39;t.</strong> The only state-transition endpoint Play exposes is <code>monetization.onetimeproducts.purchaseOptions.batchUpdateStates</code>, which takes an array.</p><p>The CLI&#39;s <code>iap state</code> handles batching transparently — you specify the YAML state and it figures out the right call. Don&#39;t try to flip a one-time purchase option&#39;s state with a per-item call; it doesn&#39;t exist.</p><h2 id="_6-regionsversion-is-required-on-every-patch" tabindex="-1">6. <code>regionsVersion</code> is required on every patch <a class="header-anchor" href="#_6-regionsversion-is-required-on-every-patch" aria-label="Permalink to &quot;6. `regionsVersion` is required on every patch&quot;">​</a></h2><p>Play&#39;s regional catalogue evolves (new countries, currency tweaks). Every <code>patch</code> and <code>create</code> requires you to declare which catalogue version you&#39;re targeting via <code>regionsVersion.version</code>, like <code>&quot;2025/03&quot;</code>.</p><p>Quirk: <strong>one-time products return this in the GET response, but subscriptions don&#39;t</strong>. The CLI&#39;s sync command resolves a shared default at startup by GETting the first YAML-listed one-time product, then uses that version for subscription patches too. <code>--regions-version</code> overrides.</p><h2 id="_7-newly-created-subscriptions-land-in-draft" tabindex="-1">7. Newly-created subscriptions land in DRAFT <a class="header-anchor" href="#_7-newly-created-subscriptions-land-in-draft" aria-label="Permalink to &quot;7. Newly-created subscriptions land in DRAFT&quot;">​</a></h2><p>When <code>iap create</code> creates a new subscription, every base plan and every offer on it lands in <code>DRAFT</code> state. They&#39;re <strong>invisible to users</strong> until you activate them.</p><p>The success message reminds you. Use <code>iap state</code> to flip them, or use Play Console for the manual flip.</p><p>This is Play&#39;s safety net — you can&#39;t accidentally ship a half-configured tier. Apple has no equivalent.</p><h2 id="_8-updatemask-is-rejected" tabindex="-1">8. <code>updateMask: &#39;*&#39;</code> is rejected <a class="header-anchor" href="#_8-updatemask-is-rejected" aria-label="Permalink to &quot;8. `updateMask: &#39;*&#39;` is rejected&quot;">​</a></h2><p>Google&#39;s standard field-mask syntax accepts <code>*</code> as &quot;all fields&quot;, but the Play monetization API specifically does NOT. You must enumerate the fields you want to update.</p><p>The CLI&#39;s default updateMasks:</p><ul><li>One-time products: <code>listings,purchaseOptions,offerTags</code></li><li>Subscriptions: <code>listings,basePlans</code></li></ul><p>If you add a new top-level field to the YAML schema, you must also add it to the updateMask string in <code>src/client.ts</code> <code>upsertOneTimeProduct</code> / <code>upsertSubscription</code>, or the field will be ignored on push.</p><h2 id="_9-one-time-offers-can-t-set-a-flat-price" tabindex="-1">9. One-time offers can&#39;t set a flat price <a class="header-anchor" href="#_9-one-time-offers-can-t-set-a-flat-price" aria-label="Permalink to &quot;9. One-time offers can&#39;t set a flat price&quot;">​</a></h2><p>Subscription offer phases support <code>free</code>, <code>price</code>, <code>absolute_discount</code>, OR <code>relative_discount</code>. One-time offers support only <code>absolute_discount</code>, <code>relative_discount</code>, OR <code>no_override</code>. <strong>No flat-price override.</strong></p><p>The YAML schema reflects this: one-time <code>offers[].regional_configs[]</code> doesn&#39;t accept <code>price</code>. Setting one in YAML will produce a typecheck error.</p><h2 id="_10-two-price-shapes-on-the-wire" tabindex="-1">10. Two price shapes on the wire <a class="header-anchor" href="#_10-two-price-shapes-on-the-wire" aria-label="Permalink to &quot;10. Two price shapes on the wire&quot;">​</a></h2><p>The new monetization API uses <code>Schema$Money { currencyCode, units, nanos }</code>. The dead-but-still-typed <code>inappproducts</code> API uses <code>Schema$Price { currency, priceMicros }</code>. Don&#39;t accidentally re-introduce the legacy shape — <code>client.ts</code> canonicalises everything to <code>Money</code> because that&#39;s what the monetization API speaks.</p><p>If you see <code>priceMicros</code> in code, it&#39;s old or wrong.</p><h2 id="_11-client-deleteedit-after-every-read-only-edit-session-call" tabindex="-1">11. <code>client.deleteEdit()</code> after every read-only edit-session call <a class="header-anchor" href="#_11-client-deleteedit-after-every-read-only-edit-session-call" aria-label="Permalink to &quot;11. `client.deleteEdit()` after every read-only edit-session call&quot;">​</a></h2><p>Some Play endpoints (listings, tracks, images) require an edit session: you start an edit, do work, then either commit or delete. The CLI&#39;s read commands start an edit implicitly when needed (<code>listListings</code>, <code>listTracks</code>, <code>listScreenshots</code>).</p><p><strong>If the read path doesn&#39;t commit, you must <code>deleteEdit()</code> afterwards.</strong> Otherwise the edit accumulates as a pending change in Play Console, visible to other operators. The MCP server does this religiously after every read; the CLI mostly doesn&#39;t because each command run is short and the edit gets garbage-collected by Play after a while — but it&#39;s still good hygiene.</p><h2 id="_12-worktree-vs-project-root" tabindex="-1">12. Worktree vs project root <a class="header-anchor" href="#_12-worktree-vs-project-root" aria-label="Permalink to &quot;12. Worktree vs project root&quot;">​</a></h2><p>Same setup as appstore-cli:</p><ul><li><strong>Project root</strong> — the main repo. Where secrets live (<code>.secret-stuff/playstore-config.yaml</code>). Shared across worktrees.</li><li><strong>Worktree root</strong> — the current branch&#39;s working directory. Where metadata lives. Per-branch.</li></ul><p>If you&#39;re not using worktrees, both roots are the same — nothing to think about.</p><h2 id="_13-the-historical-metadata-split" tabindex="-1">13. The historical metadata split <a class="header-anchor" href="#_13-the-historical-metadata-split" aria-label="Permalink to &quot;13. The historical metadata split&quot;">​</a></h2><p>This is a Lazy-Sudoku-specific quirk preserved by the defaults: IAP YAML lives at <code>l10n/metadata/play/iap.yaml</code>, but listings + screenshots + release notes live at <code>l10n/metadata/google/...</code>. The CLI has separate <code>metadata_dir</code> and <code>listings_dir</code> knobs because of this.</p><p>Greenfield projects should set both to the same directory in <code>playstore-cli.config.yaml</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata_dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">store-metadata/play</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">listings_dir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">store-metadata/play</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # unify</span></span></code></pre></div><p>When this package is extracted to its own repo, consider flipping the default so <code>listings_dir</code> matches <code>metadata_dir</code> and the split is a downstream override rather than the default.</p>',49)])])}const g=o(s,[["render",r]]);export{u as __pageData,g as default};
